<script setup>import AppLayout from '@/Layouts/AppLayout.vue';import { useForm, router } from '@inertiajs/vue3';defineOptions({layout:AppLayout});const props=defineProps({entry:Object});const form=useForm({...props.entry, birth_date: props.entry.birth_date?.substring?.(0,10) || props.entry.birth_date || ''});const del=()=>{ if(confirm('Remove this entry?')) router.delete(`/blacklist/${props.entry.id}`); }</script>
<template><section class="card max-w-2xl"><h1 class="mb-4 text-2xl font-bold">Edit blacklist entry</h1><form @submit.prevent="form.put(`/blacklist/${entry.id}`)" class="space-y-3"><div class="grid gap-3 sm:grid-cols-2"><div><label class="label">First name</label><input v-model="form.first_name" class="input"></div><div><label class="label">Last name</label><input v-model="form.last_name" class="input"></div></div><div><label class="label">ID/document number</label><input v-model="form.id_document_number" class="input"></div><div><label class="label">Location</label><input v-model="form.location" class="input"></div><div><label class="label">Reason</label><input v-model="form.reason" class="input"></div><div><label class="label">Status</label><select v-model="form.status" class="input"><option>active</option><option>expired</option><option>appealed</option></select></div><div><label class="label">Notes</label><textarea v-model="form.notes" class="input min-h-24"></textarea></div><div class="flex gap-2"><button class="btn btn-primary">Save</button><button type="button" @click="del" class="btn bg-red-500 text-white">Delete</button></div></form></section></template>
